#!/usr/bin/env node
/**
 * One-shot generator for the earth-sciences world map.
 *
 * Reads Natural Earth 110m land geometry from the `world-atlas` dev
 * dependency, decodes it via `topojson-client`, projects every
 * coordinate equirectangularly to fit an 800x400 viewBox, and writes
 * the resulting SVG path strings to a static TS file. The devDeps are
 * only needed to regenerate — the generated file has no runtime deps.
 *
 * Run with: node scripts/generate-world-paths.mjs
 */

import { readFileSync, writeFileSync } from 'node:fs'
import { resolve, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'
import { feature } from 'topojson-client'

const here = dirname(fileURLToPath(import.meta.url))
const topo = JSON.parse(
  readFileSync(resolve(here, '../node_modules/world-atlas/land-110m.json'), 'utf8'),
)
const land = feature(topo, topo.objects.land)

const VIEW_W = 800
const VIEW_H = 400

function project(lon, lat) {
  const x = ((lon + 180) / 360) * VIEW_W
  const y = ((90 - lat) / 180) * VIEW_H
  // 2 decimals is enough for a 800x400 viewBox — saves ~40% vs. full floats.
  return [x.toFixed(2), y.toFixed(2)]
}

function ringToPath(ring) {
  const parts = ring.map(([lon, lat], i) => {
    const [x, y] = project(lon, lat)
    return `${i === 0 ? 'M' : 'L'}${x},${y}`
  })
  return parts.join('') + 'Z'
}

function polygonsToPath(polygons) {
  return polygons.map((poly) => poly.map(ringToPath).join('')).join('')
}

const geometries = land.type === 'GeometryCollection' ? land.geometries : [land]
const pathParts = []
for (const g of geometries) {
  if (g.type === 'Polygon') pathParts.push(ringToPath(g.coordinates[0]), ...g.coordinates.slice(1).map(ringToPath))
  if (g.type === 'MultiPolygon') pathParts.push(polygonsToPath(g.coordinates))
}

// features can have properties that route us here too
for (const f of land.features ?? []) {
  const g = f.geometry
  if (!g) continue
  if (g.type === 'Polygon') pathParts.push(g.coordinates.map(ringToPath).join(''))
  if (g.type === 'MultiPolygon') pathParts.push(polygonsToPath(g.coordinates))
}

const d = pathParts.join('')

const output = `/**
 * Generated by scripts/generate-world-paths.mjs — do not edit by hand.
 * Source: Natural Earth 110m land geometry (public domain) via world-atlas.
 * Projected equirectangularly to fit the 800x400 map viewBox.
 */
export const WORLD_MAP_VIEW_W = ${VIEW_W}
export const WORLD_MAP_VIEW_H = ${VIEW_H}
export const WORLD_LAND_PATH =
  ${JSON.stringify(d)}
`

const outPath = resolve(here, '../app/earth-sciences/world-map-paths.ts')
writeFileSync(outPath, output)

console.log(`Wrote ${outPath}`)
console.log(`Path data: ${d.length} chars`)
